namespace FrenchVerbes.AllConstants;

public static partial class Constants
{
    public static partial class VerbDescriptions
    {
        public static partial class Regular
        {
            public static partial class Er
            {
                public const string Beneficier = "Bénéficier est un verbe régulier du premier groupe (-er) qui signifie procurer un avantage, apporter un bienfait ou tirer profit de quelque chose.";
                public const string Briller = "Briller est un verbe régulier du premier groupe (-er) qui signifie émettre de la lumière, resplendir, ou se distinguer par ses qualités, son intelligence ou ses performances. Il est employé au sens propre comme au sens figuré.";
                public const string Bombarder = "Bombarder est un verbe régulier du premier groupe (-er) qui signifie soumettre à des bombardements, ou, au sens figuré, accabler quelqu'un de questions, de messages ou de sollicitations en grand nombre.";
                public const string Bouger = "Bouger est un verbe régulier du premier groupe (-er) qui signifie se déplacer, changer de position ou de place, ou évoluer. Il présente un changement orthographique : le 'g' prend un 'e' devant 'a' et 'o' pour conserver le son [ʒ].";
                public const string Baptiser = "Baptiser est un verbe régulier du premier groupe (-er) qui signifie administrer le baptême à quelqu'un, ou, par extension, donner un nom à quelque chose ou quelqu'un de manière officielle ou affectueuse.";
                public const string Barrer = "Barrer est un verbe régulier du premier groupe (-er) qui signifie fermer un passage, bloquer une voie, ou tracer une barre sur quelque chose pour l'annuler. Il s'emploie dans des contextes de circulation, d'écriture et de navigation.";
                public const string Baisser = "Baisser est un verbe régulier du premier groupe (-er) qui signifie descendre, diminuer, réduire ou incliner vers le bas. Il s'emploie aussi de façon pronominale (se baisser) pour exprimer l'action de s'incliner vers le bas.";
                public const string Se_Baisser = "Se baisser est la forme pronominale réfléchie du verbe baisser. Il signifie s'incliner vers le bas, se courber pour atteindre quelque chose au sol. Il se conjugue avec l'auxiliaire 'être' aux temps composés.";
                public const string Bloquer = "Bloquer est un verbe régulier du premier groupe (-er) qui signifie empêcher le mouvement, le passage ou le fonctionnement de quelque chose ou de quelqu'un. Il s'emploie aussi de façon pronominale (se bloquer) pour exprimer le fait de se retrouver coincé ou d'avoir un blocage.";
                public const string Se_Bloquer = "Se bloquer est la forme pronominale réfléchie du verbe bloquer. Il signifie se coincer, se retrouver dans l'incapacité d'avancer ou de fonctionner, physiquement ou mentalement. Il se conjugue avec l'auxiliaire 'être' aux temps composés.";
                public const string Bouder = "Bouder est un verbe régulier du premier groupe (-er) qui signifie manifester son mécontentement en gardant le silence et en s'isolant, ou éviter quelque chose ou quelqu'un par désaffection.";
                public const string Briser = "Briser est un verbe régulier du premier groupe (-er) qui signifie casser, mettre en morceaux, ou interrompre brutalement quelque chose. Il s'emploie au sens propre comme au sens figuré, notamment pour exprimer la destruction d'un lien, d'un rêve ou d'un silence.";
            }
        }
    }
}
